insert into public.recipes (slug, title, icon, category, time_label, description, region, data) values
  ('bife_parmegiana_light', 'Bife à Parmegiana Light', '🍖', 'Almoço · Paulistano', '40 min', 'Versão leve da parmegiana: bife grelhado, molho de tomate caseiro e queijo minas gratinado.', 'sudeste', '{"ings":[{"n":"Filé mignon em bifes","a":"300 g"},{"n":"Molho de tomate caseiro","a":"1 xícara"},{"n":"Queijo minas fresco fatiado","a":"150 g"},{"n":"Orégano, alho, sal, pimenta","a":"a gosto"}],"steps":["Tempere os bifes com alho, sal e pimenta.","Grelhe em frigideira antiaderente por 2 min cada lado.","Transfira para refratário; cubra com molho de tomate.","Disponha queijo minas por cima e polvilhe orégano.","Gratine em forno a 200 °C por 10 min."],"tip":"Queijo minas no lugar da muçarela corta ~40% da gordura sem perder o efeito gratinado."}'::jsonb),
  ('canja_galinha_sudeste', 'Canja de Galinha', '🍲', 'Jantar · Reconfortante', '45 min', 'Caldo clássico de galinha com arroz e legumes — versão mineira simples.', 'sudeste', '{"ings":[{"n":"Peito de galinha com osso","a":"300 g"},{"n":"Arroz cru","a":"1/3 xícara"},{"n":"Cenoura, batata, abobrinha em cubos","a":"2 xícaras"},{"n":"Cebola, alho, louro, salsinha","a":"a gosto"}],"steps":["Cozinhe a galinha em 1,5 l de água com louro por 30 min.","Retire, desfie e devolva o caldo ao fogo.","Adicione arroz e cozinhe por 8 min.","Junte os legumes; cozinhe mais 10 min.","Devolva a galinha desfiada; finalize com salsinha."],"tip":"Galinha caipira dá mais sabor mas exige 20 min a mais de cozimento."}'::jsonb),
  ('feijao_arroz_branco', 'Feijão Preto com Arroz Branco', '🍛', 'Almoço · Básico', '1h', 'O prato mais brasileiro: feijão preto temperado com arroz soltinho.', 'sudeste', '{"ings":[{"n":"Feijão preto","a":"1 xícara"},{"n":"Arroz branco cru","a":"1 xícara"},{"n":"Bacon ou linguiça (opcional)","a":"50 g"},{"n":"Cebola, alho, louro, cheiro-verde","a":"a gosto"}],"steps":["Deixe o feijão de molho por 4h; cozinhe em pressão com louro por 25 min.","Refogue alho e cebola em panela separada; junte o feijão.","Para o arroz: refogue alho/cebola, acrescente o arroz e água fervente (2:1).","Cozinhe o arroz tampado por 15 min em fogo baixo.","Finalize ambos com cheiro-verde."],"tip":"Bata 1 concha de feijão no liquidificador e devolva à panela — caldo fica cremoso."}'::jsonb),
  ('feijao_tropeiro', 'Feijão Tropeiro', '🌾', 'Almoço · Mineiro', '35 min', 'Feijão carioca misturado com farinha, ovo, bacon e linguiça — prato de viagem dos tropeiros.', 'sudeste', '{"ings":[{"n":"Feijão carioca cozido escorrido","a":"2 xícaras"},{"n":"Farinha de mandioca","a":"1 xícara"},{"n":"Bacon em cubinhos","a":"100 g"},{"n":"Linguiça calabresa em rodelas","a":"100 g"},{"n":"Ovos, cebola, alho, cebolinha","a":"a gosto"}],"steps":["Frite o bacon até dourar; acrescente a linguiça.","Retire parte da gordura; refogue cebola e alho.","Bata os ovos, despeje na panela e mexa para formar pedacinhos.","Junte o feijão escorrido e misture bem.","Incorpore a farinha aos poucos mexendo sempre.","Finalize com cebolinha."],"tip":"Feijão escorrido SECO é o segredo — se tiver caldo, a farinha vira papa."}'::jsonb),
  ('lombo_feijao_preto_couve', 'Lombo Suíno Magro c/ Feijão Preto e Couve', '🍖', 'Almoço · Mineiro light', '25 min', 'Sabores da feijoada numa versão rápida e magra: lombo suíno grelhado, arroz, feijão preto e couve refogada.', 'sudeste', '{"ings":[{"n":"Lombo suíno magro em filés","a":"130 g"},{"n":"Arroz branco cozido","a":"2 col sopa"},{"n":"Feijão preto cozido","a":"3 col sopa"},{"n":"Couve em tiras finas","a":"1 xícara"},{"n":"Laranja em fatias","a":"1/2 unidade"},{"n":"Alho, sal, pimenta, azeite","a":"a gosto"}],"steps":["Tempere o lombo com alho, sal e pimenta; 10 min.","Grelhe em frigideira quente 3-4 min cada lado.","Em paralelo, refogue alho; acrescente a couve; 2 min até murchar levemente.","Aqueça feijão preto e arroz.","Monte o prato: lombo fatiado, arroz, feijão, couve, fatias de laranja."],"tip":"Lombo magro tem 8g de gordura por 100g — vs 18g das carnes de feijoada tradicional."}'::jsonb),
  ('frango_quiabo_mineiro', 'Frango Ensopado Mineiro c/ Quiabo', '🐔', 'Almoço · Mineiro light', '25 min', 'Frango ensopado rápido com quiabo — sabores mineiros sem o tempo nem o sangue do molho pardo.', 'sudeste', '{"ings":[{"n":"Peito de frango em cubos","a":"130 g"},{"n":"Quiabo em rodelas","a":"1 xícara"},{"n":"Angu de fubá (polenta mole)","a":"3 col sopa"},{"n":"Tomate, cebola, alho","a":"a gosto"},{"n":"Salada verde (acompanhamento)","a":"à vontade"},{"n":"Azeite, sal, pimenta, colorau","a":"a gosto"}],"steps":["Tempere o frango em cubos com alho, sal e colorau; 10 min.","Doure em fio de azeite; acrescente cebola e tomate picado.","Cubra com 1/2 xícara de água; cozinhe 8 min.","Adicione o quiabo em rodelas; cozinhe mais 5 min.","Em paralelo, prepare o angu: fubá em chuva no caldo quente, mexer 10 min.","Sirva o frango com angu e salada verde."],"tip":"Para o quiabo não ''babar'', lave em vinagre e seque antes de cortar em rodelas."}'::jsonb),
  ('lasanha_abobrinha_light', 'Lasanha de Abobrinha Light', '🥒', 'Jantar · Fit', '45 min', 'Lasanha sem massa — fatias finas de abobrinha, peito de frango e queijo minas.', 'sudeste', '{"ings":[{"n":"Abobrinha em fatias finas","a":"2 grandes"},{"n":"Peito de frango desfiado cozido","a":"300 g"},{"n":"Molho de tomate","a":"1 xícara"},{"n":"Queijo minas fresco","a":"200 g"},{"n":"Manjericão, alho, azeite","a":"a gosto"}],"steps":["Grelhe as fatias de abobrinha por 1 min cada lado (tira água).","Refogue o frango desfiado com alho e molho de tomate.","Num refratário, alterne camadas: abobrinha, frango, queijo minas, repetir.","Termine com queijo minas por cima.","Asse a 200 °C por 20 min até gratinar.","Finalize com manjericão fresco."],"tip":"Grelhar a abobrinha antes tira o excesso de água — senão a lasanha fica aguada."}'::jsonb),
  ('macarronada_bolonhesa', 'Macarronada Integral à Bolonhesa', '🍝', 'Almoço · Ítalo-brasileiro', '35 min', 'Massa integral com molho de carne moída magra e tomate pelado.', 'sudeste', '{"ings":[{"n":"Macarrão integral (penne ou espaguete)","a":"300 g"},{"n":"Carne moída magra","a":"300 g"},{"n":"Tomate pelado em lata","a":"1 lata"},{"n":"Cebola, alho, cenoura ralada, manjericão","a":"a gosto"}],"steps":["Doure cebola, alho e cenoura ralada em fio de azeite.","Acrescente a carne moída e refogue até secar.","Junte o tomate pelado amassado; cozinhe por 20 min.","Ajuste sal, pimenta e manjericão.","Cozinhe a massa al dente; escorra.","Sirva a massa com o molho generoso por cima."],"tip":"Cenoura ralada no molho adoça naturalmente — substitui o açúcar comum."}'::jsonb),
  ('moqueca_capixaba', 'Moqueca Capixaba', '🐟', 'Almoço · Capixaba', '35 min', 'Moqueca do ES — sem leite de coco, sem dendê, colorida com urucum e tomate.', 'sudeste', '{"ings":[{"n":"Postas de peixe branco firme","a":"400 g"},{"n":"Tomate, cebola, pimentão em rodelas","a":"a gosto"},{"n":"Urucum em pó (colorau)","a":"1 col sopa"},{"n":"Azeite, limão, coentro, alho","a":"a gosto"}],"steps":["Tempere o peixe com limão, alho, urucum e sal; deixe 15 min.","Numa panela de barro, faça camadas: cebola, tomate, pimentão, peixe.","Regue com azeite e um pouco de água.","Cozinhe tampado em fogo baixo por 20 min sem mexer.","Finalize com muito coentro fresco."],"tip":"Diferença pra baiana: NÃO leva dendê nem leite de coco — a cor vem só do urucum."}'::jsonb),
  ('omelete_queijo_minas_sudeste', 'Omelete com Queijo Minas', '🍳', 'Jantar · Rápido', '10 min', 'Omelete simples com queijo minas fresco em cubos e cebolinha.', 'sudeste', '{"ings":[{"n":"Ovos","a":"3 unidades"},{"n":"Queijo minas fresco em cubos","a":"80 g"},{"n":"Cebolinha, manteiga, sal, pimenta","a":"a gosto"}],"steps":["Bata os ovos com sal, pimenta e cebolinha.","Aqueça manteiga em frigideira antiaderente.","Despeje os ovos; quando firmar a base, adicione queijo.","Dobre ao meio e cozinhe mais 1 min.","Sirva com salada."],"tip":"Queijo minas fresco não derrete muito — cria bolsos de queijo macio no omelete."}'::jsonb),
  ('peito_frango_grelhado', 'Peito de Frango Grelhado', '🐔', 'Jantar · Fit', '20 min', 'Peito de frango grelhado simples com ervas — base de qualquer dieta.', 'sudeste', '{"ings":[{"n":"Peito de frango em filés","a":"300 g"},{"n":"Limão, alho, alecrim","a":"a gosto"},{"n":"Azeite, sal, pimenta","a":"a gosto"}],"steps":["Tempere com limão, alho amassado, alecrim, sal e pimenta; deixe 15 min.","Seque com papel-toalha antes de grelhar.","Aqueça frigideira com fio de azeite.","Grelhe 4 min cada lado em fogo médio-alto.","Deixe descansar 3 min antes de cortar."],"tip":"Bata o peito com tenderizer (ou fundo de panela) até ficar uniforme — grelha por igual."}'::jsonb),
  ('polenta_mole_frango_grelhado', 'Polenta Mole Leve c/ Frango Grelhado', '🌽', 'Almoço · Ítalo-brasileiro light', '22 min', 'Polenta mole sem queijo acompanhada de frango grelhado — combinação ítalo-brasileira mais leve, sem manteiga nem parmesão.', 'sudeste', '{"ings":[{"n":"Fubá de milho fino","a":"1/3 xícara"},{"n":"Caldo de legumes","a":"1,5 xícaras"},{"n":"Peito de frango em filés","a":"120 g"},{"n":"Salada verde c/ tomate","a":"à vontade"},{"n":"Alho, sal, pimenta, azeite","a":"a gosto"}],"steps":["Tempere o frango com alho, sal, pimenta; 10 min.","Grelhe em fio de azeite por 4 min cada lado.","Em paralelo, ferva o caldo; despeje fubá em chuva mexendo.","Cozinhe a polenta 12 min em fogo baixo, mexendo ocasionalmente.","Não adicione queijo nem manteiga (versão leve).","Sirva o frango sobre a polenta + salada de folhas e tomate."],"tip":"Polenta sem queijo e manteiga fica mais leve — o frango grelhado entrega o sabor principal."}'::jsonb),
  ('polenta_mole_tomate', 'Polenta Mole ao Molho de Tomate', '🍅', 'Jantar · Leve', '30 min', 'Polenta cremosa com molho de tomate fresco e manjericão.', 'sudeste', '{"ings":[{"n":"Fubá de milho fino","a":"1 xícara"},{"n":"Caldo de legumes","a":"4 xícaras"},{"n":"Tomates maduros picados","a":"3 unidades"},{"n":"Alho, manjericão, azeite","a":"a gosto"}],"steps":["Ferva o caldo; adicione o fubá em chuva mexendo.","Cozinhe em fogo baixo por 20 min.","Em paralelo, refogue alho em azeite; junte tomates picados.","Cozinhe o molho por 10 min.","Sirva a polenta com molho e manjericão."],"tip":"Use tomates bem maduros (preferencialmente italianos) — base doce e saborosa."}'::jsonb),
  ('quibe_assado', 'Quibe Assado', '🥖', 'Almoço · Árabe-paulistano', '1h', 'Quibe de trigo e carne moída assado no forno — versão paulistana tradicional.', 'sudeste', '{"ings":[{"n":"Trigo para quibe (bulgur fino)","a":"1 xícara"},{"n":"Carne moída magra","a":"500 g"},{"n":"Cebola ralada","a":"1 unidade"},{"n":"Hortelã picada","a":"1/2 xícara"},{"n":"Sal, pimenta síria, azeite","a":"a gosto"}],"steps":["Hidrate o trigo em água fria por 30 min; escorra apertando bem.","Misture o trigo com a carne, cebola, hortelã, sal e pimenta síria.","Amasse até ficar homogêneo (como um patê).","Espalhe numa assadeira untada; faça losangos com a faca.","Regue com azeite e asse a 200 °C por 30 min.","Sirva com iogurte natural à parte."],"tip":"Pimenta síria muda o quibe — se não tiver, misture cominho + canela + cravo moídos."}'::jsonb),
  ('sopa_feijao_macarrao', 'Sopa de Feijão com Macarrão', '🥣', 'Jantar · Reconfortante', '40 min', 'Caldo de feijão com macarrão tipo letrinha ou conchinha.', 'sudeste', '{"ings":[{"n":"Feijão carioca cozido com caldo","a":"2 xícaras"},{"n":"Macarrão tipo conchinha ou ave-maria","a":"1/2 xícara"},{"n":"Cebola, alho, bacon (opcional)","a":"a gosto"},{"n":"Cheiro-verde, pimenta","a":"a gosto"}],"steps":["Bata metade do feijão com caldo no liquidificador.","Refogue cebola, alho e bacon em panela funda.","Junte o feijão batido e o inteiro + 500 ml de água morna.","Ferva; acrescente o macarrão e cozinhe por 8 min.","Finalize com cheiro-verde."],"tip":"Não deixe descansar — macarrão em sopa cresce e vira papa se esperar demais."}'::jsonb),
  ('sopa_legumes_frango', 'Sopa de Legumes com Frango', '🥣', 'Jantar · Leve', '35 min', 'Caldo leve com variedade de legumes e frango desfiado.', 'sudeste', '{"ings":[{"n":"Peito de frango desfiado cozido","a":"200 g"},{"n":"Cenoura, chuchu, abobrinha, batata","a":"3 xícaras"},{"n":"Caldo de galinha","a":"1,5 l"},{"n":"Cebola, alho, cheiro-verde","a":"a gosto"}],"steps":["Cozinhe o frango em 1,5 l de água com cebola; desfie.","Corte todos os legumes em cubos pequenos.","Volte o caldo ao fogo; junte os legumes em ordem de firmeza.","Cozinhe até os legumes ficarem al dente (12 min).","Devolva o frango desfiado; ajuste sal.","Finalize com cheiro-verde."],"tip":"Legumes em cubos pequenos (~1cm) cozinham rápido e ficam bonitos na colher."}'::jsonb),
  ('frango_molho_tomate_brocolis', 'Frango ao Molho Rústico de Tomate c/ Brócolis', '🍗', 'Almoço · Fit', '20 min', 'Frango cozido em molho fresco de tomate com brócolis no vapor — alternativa ao strogonoff, sem creme de leite.', 'sudeste', '{"ings":[{"n":"Peito de frango em tiras","a":"130 g"},{"n":"Tomates maduros picados","a":"2 unidades"},{"n":"Brócolis em floretes","a":"1 xícara"},{"n":"Arroz branco cozido","a":"2 col sopa"},{"n":"Salada verde","a":"à vontade"},{"n":"Cebola, alho, manjericão, azeite","a":"a gosto"}],"steps":["Tempere o frango com alho e sal; 10 min.","Refogue cebola em fio de azeite; acrescente frango em tiras.","Doure por 4 min; junte os tomates picados.","Cozinhe 8 min até formar molho rústico.","Em paralelo, cozinhe brócolis no vapor por 4 min (al dente).","Finalize com manjericão fresco.","Sirva com arroz e salada."],"tip":"Tomate maduro + manjericão fresco entregam cremosidade natural sem creme de leite."}'::jsonb),
  ('tilapia_grelhada', 'Tilápia Grelhada', '🐟', 'Jantar · Fit', '15 min', 'Filé de tilápia grelhado na manteiga com limão e alho.', 'sudeste', '{"ings":[{"n":"Filé de tilápia","a":"300 g"},{"n":"Limão, alho, manteiga","a":"a gosto"},{"n":"Sal, pimenta, salsinha","a":"a gosto"}],"steps":["Tempere os filés com limão, alho, sal e pimenta; 10 min.","Aqueça manteiga em frigideira antiaderente.","Grelhe 3 min cada lado em fogo médio-alto.","Finalize com salsinha e um extra de limão."],"tip":"Tilápia é um peixe delicado — não vire antes de formar crosta ou quebra."}'::jsonb),
  ('frango_desfiado_pure_abobora', 'Frango Desfiado c/ Purê de Abóbora', '🥧', 'Jantar · Fit', '20 min', 'Frango desfiado refogado com purê de abóbora leve — jantar fit sem massa de torta nem 30 min de forno.', 'sudeste', '{"ings":[{"n":"Peito de frango desfiado cozido","a":"120 g"},{"n":"Abóbora cabotiá ou moranga","a":"200 g"},{"n":"Salada verde c/ tomate","a":"à vontade"},{"n":"Cebola, alho, azeite","a":"a gosto"},{"n":"Sal, pimenta, noz-moscada","a":"a gosto"}],"steps":["Cozinhe a abóbora em cubos por 12 min em água até amolecer.","Escorra e amasse com garfo; tempere com sal, pimenta e noz-moscada.","Refogue o frango desfiado com cebola e alho em fio de azeite.","Sirva o frango sobre o purê de abóbora.","Finalize com salada de folhas e tomate."],"tip":"Abóbora cabotiá é mais doce e cremosa — não precisa de manteiga para dar textura."}'::jsonb),
  ('vaca_atolada', 'Vaca Atolada', '🍖', 'Almoço · Mineiro', '2h', 'Costela bovina cozida com mandioca — a carne ''atola'' na mandioca amolecida.', 'sudeste', '{"ings":[{"n":"Costela bovina em pedaços","a":"800 g"},{"n":"Mandioca descascada em pedaços","a":"600 g"},{"n":"Cebola, alho, tomate, colorau","a":"a gosto"},{"n":"Cheiro-verde, louro, pimenta","a":"a gosto"}],"steps":["Tempere a costela com alho, sal, pimenta e colorau; deixe 30 min.","Doure em panela de pressão com um fio de óleo.","Junte cebola, tomate e louro; cubra com água.","Cozinhe em pressão por 40 min.","Abra; adicione a mandioca em pedaços grandes.","Cozinhe sem pressão por 30 min até a mandioca desmanchar levemente.","Finalize com cheiro-verde."],"tip":"Mandioca tem que ''atolar'' — quer dizer desmanchar um pouco para engrossar o caldo."}'::jsonb),
  ('virado_paulista', 'Virado à Paulista', '🍛', 'Almoço · Paulistano', '45 min', 'Prato clássico paulista: feijão tropeiro + arroz + couve refogada + bisteca + ovo frito + banana.', 'sudeste', '{"ings":[{"n":"Feijão tropeiro (ver outra receita)","a":"1 xícara"},{"n":"Arroz branco cozido","a":"1 xícara"},{"n":"Couve refogada em tiras","a":"1 xícara"},{"n":"Bisteca suína","a":"1 unidade"},{"n":"Ovo frito, banana frita","a":"1 cada"}],"steps":["Prepare o feijão tropeiro (ver receita separada).","Cozinhe arroz branco.","Refogue couve em tiras com alho e sal por 2 min (só aquecer).","Grelhe a bisteca temperada com alho e sal.","Frite a banana e o ovo em manteiga.","Monte o prato com todos os elementos lado a lado."],"tip":"Virado ''verdadeiro'' leva tutu de feijão (feijão batido com farinha) em vez do tropeiro seco."}'::jsonb),
  ('pao_de_queijo', 'Pão de Queijo Mineiro', '🧀', 'Café · Mineiro', '30 min', 'Pão de queijo clássico com polvilho azedo e queijo minas meia-cura — receita caseira simples.', 'sudeste', '{"ings":[{"n":"Polvilho azedo","a":"500 g"},{"n":"Queijo minas meia-cura ralado","a":"200 g"},{"n":"Leite","a":"1 xícara"},{"n":"Óleo","a":"1/2 xícara"},{"n":"Ovos","a":"2 unidades"},{"n":"Sal","a":"1 col ch"}],"steps":["Ferva o leite com o óleo e o sal.","Escalde o polvilho com a mistura quente; misture bem.","Deixe amornar; acrescente os ovos e o queijo ralado.","Amasse até ficar liso e elástico.","Faça bolinhas de ~30g e disponha em assadeira untada.","Asse a 200 °C por 20 min até dourar."],"tip":"Para ficar crocante por fora e mole por dentro, asse com a assadeira já quente."}'::jsonb),
  ('quibe_assado_paulistano', 'Quibe Assado Paulistano (150g)', '🍞', 'Almoço · Árabe-paulistano', '1h', 'Versão maior do quibe assado tradicional de SP com porção reforçada.', 'sudeste', '{"ings":[{"n":"Trigo para quibe","a":"1,5 xícaras"},{"n":"Carne moída magra","a":"700 g"},{"n":"Cebola ralada grande","a":"1 unidade"},{"n":"Hortelã picada","a":"3/4 xícara"},{"n":"Pimenta síria, sal, azeite","a":"a gosto"}],"steps":["Hidrate o trigo em água fria por 30 min; escorra apertando.","Misture todos os ingredientes até formar massa homogênea.","Espalhe em assadeira grande untada; corte em losangos.","Regue com azeite abundante.","Asse a 200 °C por 35 min até tostar as bordas.","Sirva com pão sírio e tahine."],"tip":"Pra ficar suculento, leve um copinho d''água no fundo do forno — cria vapor e não resseca."}'::jsonb);
